import { api } from 'lwc';
import { features } from 'lightning/features';
import LightningShadowBaseClass from 'lightning/shadowBaseClassPrivate';
export default class PrimitiveCustomCell extends LightningShadowBaseClass {
    @api
    types;
    @api
    columnType;
    @api
    value;
    @api
    editable;
    @api
    columnLabel;
    @api
    rowKeyValue;
    @api
    colKeyValue;
    @api
    columnSubType;
    @api
    typeAttribute0;
    @api
    typeAttribute1;
    @api
    typeAttribute2;
    @api
    typeAttribute3;
    @api
    typeAttribute4;
    @api
    typeAttribute5;
    @api
    typeAttribute6;
    @api
    typeAttribute7;
    @api
    typeAttribute8;
    @api
    typeAttribute9;
    @api
    typeAttribute10;
    @api
    typeAttribute21;
    @api
    typeAttribute22;
    @api
    cellTypeAttributes = {};
    @api
    treeAttributes = {};
    @api
    internalTabIndex;
    @api
    keyboardMode;
    @api
    wrapText;
    @api
    alignment;
    get type() {
        const { columnType } = this;
        const type = columnType === 'tree' ? this.columnSubType : columnType;
        const typeDetails = this.types.getType(type);
        return typeDetails;
    }
    render() {
        return this.type.template;
    }
    get typeAttributes() {
        if (features.enableConsolidateTypeAttributes) {
            return this.cellTypeAttributes;
        }
        const typeAttributes = this.type.typeAttributes;
        const attrs = {};
        if (Array.isArray(typeAttributes)) {
            for (let i = 0, { length } = typeAttributes; i < length; i += 1) {
                attrs[typeAttributes[i]] = this[`typeAttribute${i}`];
            }
        }
        return attrs;
    }
    @api
    getActionableElements() {
        let result = [];
        let navigable;
        const traverseShadowRoots = (element) => {
            navigable = element.matches('[data-navigation="enable"]');
            if (element.shadowRoot && navigable) {
                let shadowElements = element.shadowRoot.querySelectorAll('[data-navigation="enable"]');
                if (shadowElements.length > 0) {
                    shadowElements.forEach(traverseShadowRoots);
                }
                else {
                    result.push(element);
                }
            }
            else if (navigable) {
                result.push(element);
            }
        };
        let rootElements = this.template.querySelectorAll('[data-navigation="enable"]');
        rootElements.forEach(traverseShadowRoots);
        return result;
    }
}
